-- ⚠️ ไฟล์นี้ถูกสร้างโดย scripts/generate_mock_his_seed.py — อย่าแก้ด้วยมือ
-- ข้อมูลจำลอง (สังเคราะห์ ไม่ใช่คนจริง) — วัคซีนทั้งหมดจาก อย. (vaccine_product.csv)
-- usage ย้อนหลัง 45 วัน · คลังระดับ lot · รพ. 13 แห่ง
USE mock_hosxp;


-- ผู้ป่วยจำลอง (PII สังเคราะห์ — เลขบัตร/ชื่อไม่ใช่ของจริง)

-- master ยา/วัคซีน + รหัสกลาง TMT — วัคซีนทั้งหมด 150 รายการจาก อย.

-- การจ่ายวัคซีน 45 วันย้อนหลัง (สุ่มผู้ป่วย + จำนวน) — มี hn = PII
WITH RECURSIVE days(n) AS (
  SELECT 0 UNION ALL SELECT n + 1 FROM days WHERE n < 44)
SELECT
  CONCAT('VN', LPAD(FLOOR(RAND() * 1000000), 6, '0')) AS vn,
  ELT(1 + FLOOR(RAND() * 10),
      'HN0001','HN0002','HN0003','HN0004','HN0005',
      'HN0006','HN0007','HN0008','HN0009','HN0010') AS hn,
  d.icode,
  ELT(1 + FLOOR(RAND() * 13),
      'HOSP_001','HOSP_002','HOSP_003','HOSP_004','HOSP_005','HOSP_006','HOSP_007',
      'HOSP_008','HOSP_009','HOSP_010','HOSP_011','HOSP_012','HOSP_013') AS hospital_id,
  FLOOR(1 + RAND() * 8) AS qty,
  DATE_SUB(CURDATE(), INTERVAL days.n DAY) + INTERVAL FLOOR(RAND() * 10) HOUR AS rxdate
FROM days
JOIN (SELECT icode FROM drugitems WHERE is_vaccine = 1) d;

-- คลังระดับ lot — 1 ล็อตต่อวัคซีน จงใจวน แดง/เหลือง/เขียว ให้ VacFlow จับ

