-- Step 6: cold-chain temperature log







-- Step 7: vial state transition history












-- Step 8: on-site per-hospital stock derived from vaccine_vial

-- คลังระดับ รพ. (on-site) — สรุปจาก vaccine_vial ที่ seed ไว้ด้านบน
SELECT hospital_id AS warehouse,
       product_id  AS icode,
       lot_id      AS lot_no,
       SUM(doses_remaining) AS qty,
       MIN(DATE(effective_expiry)) AS expire_date,
       CURDATE() AS snapshot_date,
       hospital_id
FROM vaccine_vial
WHERE state IN ('DEEP_FROZEN','THAWED','OPENED')
GROUP BY hospital_id, product_id, lot_id;
